[
  {
    "file": "source/extensions/filters/http/ext_authz/ext_authz.cc",
    "line": 771,
    "severity": "high",
    "description": "In the Denied case, response headers from the ext_authz service are validated for valid characters (headerNameIsValid/headerValueIsValid), but NOT validated to reject pseudo-headers (names starting with ':'). This allows ext_authz to inject invalid response headers like ':status' or ':scheme' into the local reply, which violates HTTP semantics. The validation logic at lines 771-781 should explicitly reject any header names starting with ':'.",
    "fix_patch": "--- a/source/extensions/filters/http/ext_authz/ext_authz.cc
+++ b/source/extensions/filters/http/ext_authz/ext_authz.cc
@@ -769,6 +769,11 @@

     // Check headers are valid.
     if (config_->validateMutations()) {
+      // Response headers must not be pseudo-headers or Host
+      for (const auto& [key, value] : response->headers_to_set) {
+        if (!key.empty() && key[0] == ':') {
+          ENVOY_STREAM_LOG(trace, "Rejecting invalid response header '{}' (pseudo-header).", *decoder_callbacks_, key);
+          rejectResponse();
+          return;
+        }
       for (const auto& [key, value] : response->headers_to_set) {
         if (!Http::HeaderUtility::headerNameIsValid(key) ||
             !Http::HeaderUtility::headerValueIsValid(value)) {
@@ -779,6 +784,7 @@
           return;
         }
       }
+      }
     }

     // setResponseFlag must be called before sendLocalReply
"
  },
  {
    "file": "source/extensions/filters/http/ext_authz/ext_authz.cc",
    "line": 788,
    "severity": "high",
    "description": "In the Denied case, the modify_headers lambda (lines 788-804) removes and re-adds response header keys without validating that they are safe to remove/add. The code calls response_headers.remove() directly on keys from headers_to_set without checking if the key is a pseudo-header. While addCopy might fail gracefully, the remove() call could have unexpected behavior if attempting to remove pseudo-headers. More critically, the lambda should validate headers are removable before calling remove().",
    "fix_patch": "--- a/source/extensions/filters/http/ext_authz/ext_authz.cc
+++ b/source/extensions/filters/http/ext_authz/ext_authz.cc
@@ -787,15 +787,26 @@
         [&headers = response->headers_to_set,
          &callbacks = *decoder_callbacks_](Http::HeaderMap& response_headers) -> void {
           ENVOY_STREAM_LOG(trace,
                            "ext_authz filter added header(s) to the local response:", callbacks);
           // Firstly, remove all headers requested by the ext_authz filter, to ensure that they will
           // override existing headers.
           for (const auto& [key, _] : headers) {
+            // Skip removal of pseudo-headers, as response headers may not have them yet
+            // and removal could have unexpected side effects
+            if (!key.empty() && key[0] == ':') {
+              continue;
+            }
             response_headers.remove(Http::LowerCaseString(key));
           }
           // Then set all of the requested headers, allowing the same header to be set multiple
           // times, e.g. `Set-Cookie`.
           for (const auto& [key, value] : headers) {
+            // Skip pseudo-headers as they should not be set by ext_authz in response headers
+            if (!key.empty() && key[0] == ':') {
+              ENVOY_STREAM_LOG(trace, "Skipping pseudo-header '{}' in response headers", callbacks, key);
+              continue;
+            }
             ENVOY_STREAM_LOG(trace, " '{}':'{}'", callbacks, key, value);
             response_headers.addCopy(Http::LowerCaseString(key), value);
           }
"
  },
  {
    "file": "source/extensions/filters/http/ext_authz/ext_authz.cc",
    "line": 613,
    "severity": "medium",
    "description": "Malformed ENVOY_STREAM_LOG format string. Line 613 has format string "'{}'" which appears to be incomplete or truncated. Based on context of similar logging statements elsewhere in the file (e.g., line 520 with "'{}:'{}'" and line 597 with "Ignoring invalid header removal '{}'."), this log statement should include a descriptive message prefix like 'removing header' or similar descriptive text before the placeholder.",
    "fix_patch": "--- a/source/extensions/filters/http/ext_authz/ext_authz.cc
+++ b/source/extensions/filters/http/ext_authz/ext_authz.cc
@@ -610,7 +610,7 @@
       case CheckResult::OK:
         ENVOY_STREAM_LOG(trace, "'{}'", *decoder_callbacks_, key);
         request_headers_->remove(lowercase_key);
         break;"
  }
]

